import { tokenizeNative, parseDocumentNative, serializeNative } from "./native/xml.bind.js";

export function tokenizeXml(input) {
  return tokenizeNative(input);
}

export function parseXml(input) {
  return parseDocumentNative(input);
}

export function serializeXml(node) {
  return serializeNative(node, undefined);
}

export function serializeXmlWithOptions(node, options) {
  return serializeNative(node, options);
}
